using Microsoft.UI.Xaml; using Microsoft.UI.Xaml.Controls; using Windows.System;
namespace Parsis.AutoTrader.App.Pages; public sealed partial class SettingsPage:Page{private readonly AppState S=AppState.Current;public SettingsPage(){InitializeComponent();ThemeToggle.IsOn=S.Settings.Theme=="Dark";NotificationToggle.IsOn=S.Settings.WindowsNotifications;DuplicateToggle.IsOn=S.Settings.DuplicateFilter;DeviceText.Text="Device ID: "+S.License.DeviceId;}private async void Activate_Click(object sender,RoutedEventArgs e){var st=S.License.InstallLicense(LicenseBox.Text);DeviceText.Text=$"{st.Message} • {st.ExpiresAt:u}";await Task.CompletedTask;}private async void Buy_Click(object sender,RoutedEventArgs e)=>await Launcher.LaunchUriAsync(new Uri("https://t.me/parsislic"));private async void Save_Click(object sender,RoutedEventArgs e){S.Settings.Theme=ThemeToggle.IsOn?"Dark":"Light";S.Settings.WindowsNotifications=NotificationToggle.IsOn;S.Settings.DuplicateFilter=DuplicateToggle.IsOn;await S.SettingsService.SaveAsync(S.Settings);}}
